/**
 * Generated by `createservice subscription.UpdateSubscriptionContextPaymentMethodService --type mutations`
 */
const { throwAuthenticationError } = require('@open-condo/keystone/apolloErrorFormatter')
const { getById } = require('@open-condo/keystone/schema')

const { checkPermissionsInEmployedOrRelatedOrganizations } = require('@condo/domains/organization/utils/accessSchema')

async function canUpdateSubscriptionContextPaymentMethod ({ authentication: { item: user }, args, context }) {
    if (!user) return throwAuthenticationError()
    if (user.deletedAt) return false
    if (user.isAdmin || user.isSupport) return true

    const subscriptionContextWhere = args.data?.subscriptionContext
    if (!subscriptionContextWhere?.id) return false

    const subscriptionContext = await getById('SubscriptionContext', subscriptionContextWhere.id)
    if (!subscriptionContext || subscriptionContext.deletedAt) return false

    const organizationId = subscriptionContext.organization
    if (!organizationId) return false

    return await checkPermissionsInEmployedOrRelatedOrganizations(context, user, organizationId, 'canManageSubscriptions')
}

/*
  Rules are logical functions that used for list access, and may return a boolean (meaning
  all or no items are available) or a set of filters that limit the available items.
*/
module.exports = {
    canUpdateSubscriptionContextPaymentMethod,
}